// ─────────────────────────────────────────────
// VHSYS :: employers_plus
// Rota   : POST /employers_plus
// Fase 4 : Fluxo EMPLOYERS completo
// ─────────────────────────────────────────────
// Input  : { data: { dependents: [{ EmployeeId, Nome, Parentesco, ... }] } }
// Output : { message: string, dependents_updated: number } HTTP 201
// Banco  : DELETE dependentes antigos + INSERT novos por id_funcionario
// Chave  : id_funcionario (linkagem)
// ─────────────────────────────────────────────

const body = $input.first().json.body || $input.first().json;

if (!body.data) {
  return {
    _valid: false,
    statusCode: 400,
    body: { ok: false, error: 'Missing required field: data' }
  };
}

if (!body.data.dependents || !Array.isArray(body.data.dependents)) {
  return {
    _valid: false,
    statusCode: 400,
    body: { ok: false, error: 'Missing or invalid dependents array' }
  };
}

const dependents = body.data.dependents;

console.log(JSON.stringify({
  timestamp: new Date().toISOString(),
  route: 'employers_plus',
  event: 'input_validated',
  dependents_count: dependents.length,
  level: 'info'
}));

return { _valid: true, dependents };

// Agrupa dependentes por id_funcionario para processamento eficiente
const ctx = $input.first().json;
const dependents = ctx.dependents;

// Helper para formatar CPF
function formatCpf(cpf) {
  if (!cpf) return '';
  const cleaned = String(cpf).replace(/\D/g, '');
  if (cleaned.length === 11) {
    return cleaned.replace(/(\d{3})(\d{3})(\d{3})(\d{2})/, '$1.$2.$3-$4');
  }
  return cpf;
}

// Helper para converter data
function parseDate(dateStr) {
  if (!dateStr) return null;
  const date = new Date(dateStr);
  return isNaN(date.getTime()) ? null : date.toISOString().split('T')[0];
}

// Agrupa dependentes por funcionário
const groupedByEmployee = {};
dependents.forEach(dep => {
  const empId = String(dep.EmployeeId || '').trim();

  if (!empId) {
    console.log(JSON.stringify({
      timestamp: new Date().toISOString(),
      route: 'employers_plus',
      event: 'dependent_skipped_no_employee_id',
      dependent_data: dep,
      level: 'warn'
    }));
    return;
  }

  if (!groupedByEmployee[empId]) {
    groupedByEmployee[empId] = [];
  }

  groupedByEmployee[empId].push({
    nome: String(dep.Nome || '').trim(),
    parentesco: String(dep.Parentesco || '').trim(),
    data_nascimento: parseDate(dep.DataNascimento),
    cpf: formatCpf(dep.Cpf)
  });
});

// Converte para array de funcionários com seus dependentes
const employeesWithDependents = Object.keys(groupedByEmployee).map(empId => ({
  id_funcionario: empId,
  dependents: groupedByEmployee[empId]
}));

console.log(JSON.stringify({
  timestamp: new Date().toISOString(),
  route: 'employers_plus',
  event: 'dependents_grouped',
  employees_with_dependents: employeesWithDependents.length,
  total_dependents: dependents.length,
  level: 'info'
}));

return employeesWithDependents;

// Recupera dados do funcionário e dependentes do contexto anterior
const employeeData = $input.first().json;
const empWithDeps = $('Group Dependents by Employee').all()
  .find(item => item.json.id_funcionario === employeeData.id_funcionario);

if (!empWithDeps) {
  return {
    id_funcionario: employeeData.id_funcionario,
    dependents: [],
    _skip: true
  };
}

return {
  id_funcionario: employeeData.id_funcionario,
  nome_funcionario: employeeData.nome,
  dependents: empWithDeps.json.dependents,
  _skip: false
};

// Expande dependentes para inserção individual
const ctx = $input.first().json;
const empId = ctx.id_funcionario;
const dependents = ctx.dependents || [];

return dependents.map(dep => ({
  id_funcionario: empId,
  nome: dep.nome,
  parentesco: dep.parentesco,
  data_nascimento: dep.data_nascimento,
  cpf: dep.cpf
}));

