INSERT INTO auxiliary.dependentes (
  id_funcionario, nome, parentesco, data_nascimento, 
  cpf, created_at, updated_at
) VALUES (
  $1, $2, $3, $4::date, $5,
  (NOW() AT TIME ZONE 'America/Sao_Paulo')::timestamp,
  (NOW() AT TIME ZONE 'America/Sao_Paulo')::timestamp
)
RETURNING id_funcionario, nome, parentesco;

