// Conta registros inseridos e constrói resposta
const insertedRecords = $input.all()
  .filter(item => item.json && item.json.nome)
  .length;

console.log(JSON.stringify({
  timestamp: new Date().toISOString(),
  route: 'employers_plus',
  event: 'dependents_processed',
  dependents_updated: insertedRecords,
  level: 'info'
}));

// statusCode 201 — preserva compatibilidade com Flask original
return {
  statusCode: 201,
  body: {
    message: 'Dependents data updated successfully',
    dependents_updated: insertedRecords
  }
};

// Funcionário não existe - erro
const ctx = $('Group Dependents by Employee').all()
  .find(item => item.json.id_funcionario === $input.first().json.id_funcionario);

const empId = ctx ? ctx.json.id_funcionario : 'unknown';

console.log(JSON.stringify({
  timestamp: new Date().toISOString(),
  route: 'employers_plus',
  event: 'employee_not_found',
  id_funcionario: empId,
  level: 'error'
}));

return {
  statusCode: 400,
  body: { 
    ok: false, 
    error: 'Employee not found', 
    message: `Employee with ID ${empId} does not exist` 
  }
};

// Erro de validação
const input = $input.first().json;
return {
  statusCode: input.statusCode || 400,
  body: input.body || { ok: false, error: 'Validation failed' }
};

// Erro de banco
const errData = $input.first().json;

console.log(JSON.stringify({
  timestamp: new Date().toISOString(),
  route: 'employers_plus',
  event: 'db_error',
  message: errData.message || 'Unknown DB error',
  level: 'error'
}));

return {
  statusCode: 500,
  body: { ok: false, error: 'Database error', message: 'Could not update dependents data' }
};

// Return the response data as-is
const response = $input.first().json;
return response;
